import React from 'react';

const PropertyCard = ({ property }) => {
  return (
    <div className="w-[280px] bg-white rounded-2xl overflow-hidden shadow-premium transition-all duration-500 border border-transparent hover:border-[#386c8c]/20 group">
      <div className="h-56 w-full relative">
        <img src={property.mainImage} alt={property.title} className="w-full h-full object-cover" />
        <div className="absolute top-4 left-4 bg-[#121363]/80 backdrop-blur-md text-[#F0EEE9] text-[10px] tracking-widest font-medium px-3 py-1 rounded-sm uppercase">
          {property.tags[0]}
        </div>
      </div>

      <div className="p-6">
        <h4 className="text-[#121363] font-light text-lg leading-snug mb-2 h-14 overflow-hidden uppercase tracking-tight">
          {property.title}
        </h4>
        <p className="text-[#386c8c] font-medium text-lg mb-6">
          {property.price}
        </p>
        
        <div className="flex justify-between text-[#adaba5] text-[11px] mb-6 tracking-widest border-t border-[#F0EEE9] pt-4 uppercase">
          <span>{property.beds} Dorms</span>
          <span>{property.area}</span>
        </div>

        <button className="w-full bg-[#121363] text-[#F0EEE9] text-[10px] tracking-[0.2em] font-bold py-4 rounded-lg shadow-xl shadow-[#121363]/20 hover:bg-[#386c8c] transition-all uppercase">
          Ver Detalles
        </button>
      </div>
    </div>
  );
};

export default PropertyCard;
